// Helper function to read a full EXT4 block (4096 bytes)
// 辅助函数：读取完整的EXT4块（4096字节）
// blockno: 要读取的块号，从0开始（物理块号，不是逻辑块号）
// buf: 存储读取数据的目标缓冲区
static void
ext4_read_full_block(uint dev, uint blockno, char *buf)
{
#ifdef __loongarch__
    // Use single large virtio request for the whole block
    // Sector number in 512-byte units: blockno * (blocksize / 512)
    virtio_disk_rw_large(dev, blockno * (esbi[dev].blocksize / 512), buf,
                         esbi[dev].blocksize, 0);
#else
    uint sectors_per_block = esbi[dev].blocksize / BSIZE;
    uint i;
    struct buf *bp;
    for (i = 0; i < sectors_per_block; i++) {
        bp = bread(dev, blockno * sectors_per_block + i);
        memmove(buf + i * BSIZE, bp->data, BSIZE);
        brelse(bp);
    }
#endif
}

static void
ext4_write_full_block(uint dev, uint blk, char *src)
{
#ifdef __loongarch__
    // Use single large virtio request for the whole block
    // Sector number in 512-byte units: blk * (blocksize / 512)
    virtio_disk_rw_large(dev, blk * (esbi[dev].blocksize / 512), src,
                         esbi[dev].blocksize, 1);
#else
    uint sectors_per_block = esbi[dev].blocksize / BSIZE;
    for (uint s = 0; s < sectors_per_block; s++) {
        struct buf *bp = bread(dev, blk * sectors_per_block + s);
        memmove(bp->data, src + s * BSIZE, BSIZE);
        bwrite(bp);
        brelse(bp);
    }
#endif
}

